'use client';

import { useState, useRef, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import styles from './intake.module.css';
import { Send, User, Bot, Sparkles, Calendar, MessageCircle, ArrowRight, Eye } from 'lucide-react';
import { useSelection } from '@/context/SelectionContext';

interface Coach {
    id: string;
    name: string;
    title: string;
    avatar: string;
    specialties: string[];
    nextAvailable: string;
}

interface Message {
    role: 'user' | 'assistant';
    content: string;
    matches?: {
        message: string;
        coaches: Coach[];
    };
}

export default function IntakeChat() {
    const [messages, setMessages] = useState<Message[]>([
        {
            role: 'assistant',
            content: "Hej. Jag är här för att hjälpa dig hitta rätt stöd. Berätta lite om vad du går igenom just nu."
        }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);
    const router = useRouter();
    const { setSelectedCoach } = useSelection();

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const handleAction = (coach: Coach, action: 'profile' | 'chat' | 'book') => {
        setSelectedCoach(coach);
        if (action === 'chat') router.push(`/chat/${coach.id}`);
        if (action === 'book') router.push(`/book/${coach.id}`);
        if (action === 'profile') router.push(`/coaches/${coach.id}`);
    };

    const fetchMatches = async (userInput: string) => {
        try {
            const res = await fetch('/api/ai/match', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ userInput }),
            });
            return await res.json();
        } catch (e) {
            return { message: "Jag har hittat coacher som kan passa dig.", coaches: [] };
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || isLoading) return;

        const currentInput = input;
        const userMessage: Message = { role: 'user', content: currentInput };
        setMessages(prev => [...prev, userMessage]);
        setInput('');
        setIsLoading(true);

        try {
            const chatResponse = await fetch('/api/ai/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ messages: [...messages, userMessage] }),
            });

            const matchData = await fetchMatches(messages.concat(userMessage).map(m => m.content).join(' '));

            if (!chatResponse.body) throw new Error('No response body');
            const reader = chatResponse.body.getReader();
            const decoder = new TextDecoder();
            let assistantContent = '';

            setMessages(prev => [...prev, { role: 'assistant', content: '' }]);

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                assistantContent += decoder.decode(value);
                setMessages(prev => {
                    const updated = [...prev];
                    updated[updated.length - 1] = { role: 'assistant', content: assistantContent };
                    return updated;
                });
            }

            // Final message with matches
            setMessages(prev => [
                ...prev,
                {
                    role: 'assistant',
                    content: matchData.message,
                    matches: matchData
                }
            ]);

        } catch (error) {
            console.error('Chat error:', error);
            setMessages(prev => [...prev, { role: 'assistant', content: "Något gick fel. Försök igen." }]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className={styles.container}>
            <div className={styles.chatWindow}>
                <div className={styles.messages} ref={scrollRef}>
                    {messages.map((msg, idx) => (
                        <div key={idx} className={styles.messageGroup}>
                            {msg.content && (
                                <div className={`${styles.messageWrapper} ${styles[msg.role]}`}>
                                    <div className={styles.avatar}>
                                        {msg.role === 'assistant' ? <Bot size={20} /> : <User size={20} />}
                                    </div>
                                    <div className={styles.bubble}>
                                        {msg.content}
                                    </div>
                                </div>
                            )}

                            {msg.matches && (
                                <div className={styles.matchContainer}>
                                    {msg.matches.coaches.map((coach) => (
                                        <div key={coach.id} className={styles.coachCard}>
                                            <div className={styles.coachHeader}>
                                                <img src={coach.avatar} alt={coach.name} className={styles.coachAvatar} />
                                                <div>
                                                    <p className={styles.coachName}>{coach.name}</p>
                                                    <p className={styles.coachTitle}>{coach.title}</p>
                                                </div>
                                            </div>
                                            <div className={styles.coachActions}>
                                                <button onClick={() => handleAction(coach, 'profile')} className={styles.viewAction}><Eye size={14} /> Visa profil</button>
                                                <button onClick={() => handleAction(coach, 'chat')} className={styles.chatAction}><MessageCircle size={14} /> Starta chatt</button>
                                                <button onClick={() => handleAction(coach, 'book')} className={styles.bookAction}><Calendar size={14} /> Boka tid</button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    ))}
                    {isLoading && messages[messages.length - 1].role === 'user' && (
                        <div className={`${styles.messageWrapper} ${styles.assistant}`}>
                            <div className={styles.avatar}>
                                <Sparkles size={20} className={styles.pulse} />
                            </div>
                            <div className={styles.bubble}>
                                Hittar coacher som kan passa dig...
                            </div>
                        </div>
                    )}
                </div>

                <form onSubmit={handleSubmit} className={styles.inputArea}>
                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        placeholder="Beskriv vad du vill ha stöd med..."
                        className={styles.input}
                        disabled={isLoading}
                    />
                    <button type="submit" className={styles.sendBtn} disabled={isLoading || !input.trim()}>
                        <Send size={20} />
                    </button>
                </form>
            </div>

            <div className={styles.sidebar}>
                <div className={styles.sideCard}>
                    <h3>Din trygga plats</h3>
                    <p>Ta din tid. Du behöver inte förklara allt på en gång.</p>
                </div>

                <div className={styles.privacyNote}>
                    Dina samtal är privata. AI:n hjälper till med matchning. Du väljer vad som händer sen.
                </div>

                <div className={styles.guideCard}>
                    <h4>Nästa steg</h4>
                    <p>Efter att du beskrivit din situation introducerar vi dig för experter som kan hjälpa.</p>
                    <ArrowRight size={20} style={{ marginTop: 'var(--spacing-sm)', color: 'var(--accent-sage)' }} />
                </div>
            </div>
        </div>
    );
}
